const leads = $input.first().json;
const arr = Array.isArray(leads) ? leads : [leads];
const lead = arr[0];
if (!lead || !lead.id) return [];

const coleta = $('Coleta').first().json;

// Derivar resultado_alvo do segmento se não estiver preenchido
const segmentoResultadoMap = {
  'hamburgueria': 'pedidos e clientes na loja',
  'restaurante': 'pedidos e clientes na loja',
  'delivery': 'pedidos',
  'clinica': 'agendamentos e pacientes',
  'estetica': 'agendamentos',
  'escola': 'matrículas e alunos',
  'curso': 'matrículas e alunos',
  'aviacao': 'alunos e matrículas',
  'academia': 'alunos',
  'comercio': 'vendas e clientes na loja',
  'loja': 'vendas',
  'servico': 'novos clientes e agendamentos'
};

const segLower = (lead.segmento || '').toLowerCase();
let resultado_alvo = lead.resultado_alvo;
if (!resultado_alvo) {
  for (const [key, value] of Object.entries(segmentoResultadoMap)) {
    if (segLower.includes(key)) { resultado_alvo = value; break; }
  }
  resultado_alvo = resultado_alvo || 'novos clientes';
}

return [{
  json: {
    lead_id: lead.id,
    lead_nome: lead.nome_fantasia || lead.nome || coleta.nome,
    segmento: lead.segmento || '',
    cidade: lead.cidade || '',
    lead_status: lead.status || 'novo',
    lead_email: lead.email || null,
    resultado_alvo,
    historico_resumido: lead.historico_resumido || '',
    mensagem: coleta.mensagem,
    telefone: coleta.telefone,
    instance: coleta.instance,
    is_bot: lead.is_bot || null
  }
}];

const agentOutput = $input.first().json.output || '';
const lead = $('Set Lead Data').first().json;

const agendarMatch = agentOutput.match(/\[\[AGENDAR:(\d)\]\]/);
const STATUS_PERMITE_AGENDAR = ['qualificado', 'qualificando'];
const desqualificado = agentOutput.includes('[[DESQUALIFICADO]]');
const aguardandoDecisor = agentOutput.includes('[[AGUARDANDO_DECISOR]]');
const leadQualificado = agentOutput.includes('[[QUALIFICADO]]');
const contatoHumano = agentOutput.includes('[[CONTATO_HUMANO]]');
const podeAgendar = !!agendarMatch && (STATUS_PERMITE_AGENDAR.includes(lead.lead_status) || leadQualificado);
const primeiraResposta = lead.lead_status === 'abordado';
const emailMatch = agentOutput.match(/\[\[EMAIL_CAPTURADO:([^\]]+)\]\]/);
const emailCapturado = emailMatch ? emailMatch[1].trim() : null;
const emails = emailCapturado
  ? emailCapturado.split(',').map(e => e.trim()).filter(Boolean)
  : (lead.lead_email ? [lead.lead_email] : []);
const emailFinal = emails.length > 0 ? emails[0] : null;

// Usar slots reais do Processar Slots ou fallback hardcoded
let slotsData = [];
try { slotsData = $('Processar Slots').first().json.slots || []; } catch(e) {}
if (slotsData.length === 0) {
  const BR = 3;
  const d = new Date(); d.setUTCDate(d.getUTCDate()+1); d.setUTCHours(0,0,0,0);
  while(d.getUTCDay()===0||d.getUTCDay()===6) d.setUTCDate(d.getUTCDate()+1);
  const s1 = new Date(d); s1.setUTCHours(8+BR,30,0,0);
  const s2 = new Date(d); s2.setUTCHours(16+BR,0,0,0);
  slotsData = [
    {label:'amanhã às 8h30',startISO:s1.toISOString(),endISO:new Date(s1.getTime()+30*60000).toISOString()},
    {label:'amanhã às 16h', startISO:s2.toISOString(),endISO:new Date(s2.getTime()+30*60000).toISOString()}
  ];
}

let slotStart = null, slotEnd = null, slotLabel = '';
if (agendarMatch) {
  const idx = Math.min(parseInt(agendarMatch[1]) - 1, slotsData.length - 1);
  slotStart = slotsData[idx].startISO;
  slotEnd = slotsData[idx].endISO;
  slotLabel = slotsData[idx].label;
}

let novoStatus = null;
if (podeAgendar) novoStatus = 'agendado';
else if (desqualificado) novoStatus = 'desqualificado';
else if (contatoHumano) novoStatus = 'aguardando_contato';
else if (aguardandoDecisor) novoStatus = 'aguardando_decisor';
else if (leadQualificado) novoStatus = 'qualificado';
else if (primeiraResposta) novoStatus = 'qualificando';

// Notificar Sara quando precisar de contato humano
if (contatoHumano) {
  try {
    await fetch('https://domesticram-n8n.cloudfy.live/webhook/reuniao-agendada-yonzza', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        tipo: 'contato_humano',
        lead_nome: lead.lead_nome,
        segmento: lead.segmento,
        telefone: lead.telefone,
        historico: agentOutput.replace(/\[\[.*?\]\]/g, '').trim()
      })
    });
  } catch(e) {}
}

return [{
  json: {
    lead_id: lead.lead_id,
    lead_nome: lead.lead_nome,
    lead_email: emailFinal,
    email_capturado: emailCapturado,
    emails: emails,
    segmento: lead.segmento,
    telefone: lead.telefone,
    instance: lead.instance,
    historico_atual: lead.historico_resumido || '',
    tem_agendar: podeAgendar,
    tem_contato_humano: contatoHumano,
    slot_start: slotStart,
    slot_end: slotEnd,
    slot_label: slotLabel,
    novo_status: novoStatus,
    agent_output: agentOutput
  }
}];

const agentOutput = $('Verificar Ações').first().json.agent_output || '';

const cleaned = agentOutput
  .replace(/\[\[AGENDAR:\d\]\]/g, '')
  .replace(/\[\[DESQUALIFICADO\]\]/g, '')
  .replace(/\[\[AGUARDANDO_DECISOR\]\]/g, '')
  .replace(/\[\[CONTATO_HUMANO\]\]/g, '')
  .replace(/\[\[EMAIL_CAPTURADO:[^\]]+\]\]/g, '')
  .replace(/\[\[QUALIFICADO\]\]/g, '')
  .trim();

const partes = cleaned.split(/\\/)
  .map(s => s.trim())
  .filter(s => s.length > 0);

return partes.map(item => ({ json: { item } }));

const allEvents = $input.all().map(i => i.json);
const BR = 3;
// Janelas Comercial 2 (8h30-10h, 16h-17h) e Extra (17h-18h)
const JANELAS = [
  { label: '8h30', h: 8,  m: 30 },
  { label: '16h',  h: 16, m: 0  },
  { label: '17h',  h: 17, m: 0  }
];
// Sexta: só manhã (Comercial 2 8h30-10h), reunião de 30min → até 10h início (termina 10h30)
const JANELAS_SEXTA = [
  { label: '8h30', h: 8,  m: 30 },
  { label: '9h',   h: 9,  m: 0  },
  { label: '9h30', h: 9,  m: 30 },
  { label: '10h',  h: 10, m: 0  }
];
const BLOCOS_AGENDA = ['Comercial 1','Comercial 2','Operacional','Atendimento 1','Atendimento 2','Almoço','Pausa','Extra'];

function isUtil(d) { const dia = d.getUTCDay(); return dia >= 1 && dia <= 5; }
function isSexta(d) { return d.getUTCDay() === 5; }

const amanha = new Date();
amanha.setUTCDate(amanha.getUTCDate() + 1);
amanha.setUTCHours(0, 0, 0, 0);

const diasUteis = [];
let cursor = new Date(amanha);
while (diasUteis.length < 5) {
  if (isUtil(cursor)) diasUteis.push(new Date(cursor));
  cursor = new Date(cursor);
  cursor.setUTCDate(cursor.getUTCDate() + 1);
}

// Separar dias: Seg-Qui têm prioridade; Sexta só entra se necessário
const diasPrioritarios = diasUteis.filter(d => !isSexta(d));
const diasSexta = diasUteis.filter(d => isSexta(d));

function buscarSlotsNoDia(dia, janelas) {
  const encontrados = [];
  for (const janela of janelas) {
    const inicio = new Date(dia);
    inicio.setUTCHours(janela.h + BR, janela.m, 0, 0);
    const fim = new Date(inicio.getTime() + 30 * 60 * 1000);
    const temConflito = allEvents.some(ev => {
      if (!ev.start) return false;
      if (ev.transparency === 'transparent') return false;
      const nome = (ev.summary || '');
      if (BLOCOS_AGENDA.some(b => nome.includes(b))) return false;
      const evInicio = new Date(ev.start.dateTime || ev.start.date);
      const evFim = new Date(ev.end ? (ev.end.dateTime || ev.end.date) : evInicio.getTime() + 3600000);
      return evInicio < fim && evFim > inicio;
    });
    if (!temConflito) {
      const nomes = ['dom','seg','ter','qua','qui','sex','sáb'];
      const nomeDia = nomes[dia.getUTCDay()];
      const dd = String(dia.getUTCDate()).padStart(2,'0');
      const mm = String(dia.getUTCMonth() + 1).padStart(2,'0');
      encontrados.push({ label: `${nomeDia} ${dd}/${mm} ${janela.label}`, startISO: inicio.toISOString(), endISO: fim.toISOString() });
    }
  }
  return encontrados;
}

// Janelas completas com todos os slots de 30min disponíveis
const JANELA_MANHA = [
  { label: '8h30', h: 8, m: 30 },
  { label: '9h',   h: 9, m: 0  },
  { label: '9h30', h: 9, m: 30 }
];
const JANELA_TARDE = [
  { label: '16h',   h: 16, m: 0  },
  { label: '16h30', h: 16, m: 30 },
  { label: '17h',   h: 17, m: 0  },
  { label: '17h30', h: 17, m: 30 }
];

// Retorna o primeiro slot livre do dia dentro da janela
function buscarPrimeiroSlotLivre(dia, janelas) {
  const slots = buscarSlotsNoDia(dia, janelas);
  return slots.length > 0 ? slots[0] : null;
}

const slotsManha = [];
const slotsTarde = [];

for (const dia of diasPrioritarios) {
  if (slotsManha.length < 2) {
    const slot = buscarPrimeiroSlotLivre(dia, JANELA_MANHA);
    if (slot) slotsManha.push(slot);
  }
  if (slotsTarde.length < 2) {
    const slot = buscarPrimeiroSlotLivre(dia, JANELA_TARDE);
    if (slot) slotsTarde.push(slot);
  }
}

// Fallback sexta para manhã se necessário
if (slotsManha.length === 0 && diasSexta.length > 0) {
  for (const dia of diasSexta) {
    const slot = buscarPrimeiroSlotLivre(dia, JANELAS_SEXTA);
    if (slot) { slotsManha.push(slot); break; }
  }
}

// Montar par ideal: 1 manhã + 1 tarde, dias diferentes se possível
const slotsFinais = [];
if (slotsManha.length > 0 && slotsTarde.length > 0) {
  const m = slotsManha[0];
  const mDate = m.label.split(' ')[1];
  const tDiff = slotsTarde.find(s => s.label.split(' ')[1] !== mDate);
  slotsFinais.push(m, tDiff || slotsTarde[0]);
} else if (slotsManha.length >= 2) {
  slotsFinais.push(...slotsManha.slice(0, 2));
} else if (slotsTarde.length >= 2) {
  slotsFinais.push(...slotsTarde.slice(0, 2));
} else {
  slotsFinais.push(...slotsManha, ...slotsTarde);
}

// Fallback absoluto
if (slotsFinais.length === 0) {
  const fb = new Date(amanha);
  fb.setUTCHours(8 + BR, 30, 0, 0);
  slotsFinais.push({ label: 'amanhã às 8h30', startISO: fb.toISOString(), endISO: new Date(fb.getTime() + 30 * 60 * 1000).toISOString() });
}

// Slots Extra (17h30 e 18h) — só entram em todos_slots_texto, nunca no top2
const JANELA_EXTRA = [
  { label: '17h30', h: 17, m: 30 },
  { label: '18h',   h: 18, m: 0  }
];
const slotsExtra = [];
for (const dia of diasPrioritarios) {
  for (const janela of JANELA_EXTRA) {
    const slot = buscarSlotsNoDia(dia, [janela]);
    if (slot.length > 0) slotsExtra.push(slot[0]);
  }
}

const top2 = slotsFinais.slice(0, 2);
const slots_texto = top2.map(s => s.label).join(' ou ');
const todos_slots_texto = [...slotsFinais, ...slotsExtra].map(s => s.label).join(', ');
return [{ json: { slots: slotsFinais, slots_texto, todos_slots_texto } }];

// Une todos os itens do Merge em 1 item com todos os campos
const allItems = $input.all();
const combined = {};
for (const item of allItems) {
  Object.assign(combined, item.json);
}
return [{ json: combined }];

const lead = $input.first().json;
const msgOrig = lead.mensagem || '';
const msg = msgOrig.toLowerCase();

const HIGH = [
  'menudino.com','saipos.com','goomer.app','anota.ai/m','cardapioweb.com',
  'deli.com.br','booksy.com',
  'assistente virtual','autoatendimento',
  'protocolo de atendimento: #',
  'fiquei confuso sobre o que você deseja',
  'fiquei em dúvida sobre sua solicitação'
];

const MED = [
  'seja bem-vindo','seja bem-vinda',
  'retornaremos em breve','retornamos em breve','em instantes retornaremos',
  'nossa equipe retornará','nossa equipe entrará em contato',
  'vou encaminhar para o responsável','vou encaminhar isso para',
  'horário de funcionamento',
  'cardápio digital'
];

const hasMenu = msgOrig.includes('⃣') || /\n[1-9]\s*[-–:)]/.test(msgOrig) || /^[1-9]\s*[-–:)]/m.test(msgOrig);

const deliveryLinks = ['menudino','saipos.com','goomer.app','anota.ai/m','cardapioweb','deli.com.br','booksy'];
const isDeliveryLink = deliveryLinks.some(d => msg.includes(d));

const highHit = HIGH.some(p => msg.includes(p));
const medCount = MED.filter(p => msg.includes(p)).length;

let isBot = highHit || hasMenu || medCount >= 2;
let botType = null;
let escapeOption = null;

if (isBot) {
  if (lead.is_bot === '1x') {
    botType = 'infinito';
  } else if (isDeliveryLink && !hasMenu) {
    botType = 'infinito';
  } else {
    botType = '1x';
  }

  if (botType !== 'infinito') {
    if (msg.includes('falar com atendente')) {
      escapeOption = 'Falar com atendente';
    } else if (msg.includes('atendente') && hasMenu) {
      escapeOption = 'Atendente';
    } else if (hasMenu) {
      const finMatch = msgOrig.match(/([1-9])[\s\S]{0,8}(financeiro|vendas|cursos|comercial)/i);
      escapeOption = finMatch ? finMatch[1] : '1';
    }
  }
}

return [{ json: { ...lead, is_bot_detected: isBot, bot_type: isBot ? botType : null, bot_escape_option: escapeOption || null, tem_escape: !!(isBot && escapeOption && botType !== 'infinito') } }];
